#include "biblia.h"

void Biblia::CarregarObadias(Biblia* b) {
    b->dados[OBADIAS].nome = wxT("Obadias");

    b->dados[OBADIAS].capitulos[1].versos[1] = wxT("Visão de Obadias. Assim diz o Senhor Deus a respeito de Edom: Temos ouvido novas da parte do Senhor, e por entre as nações foi enviado um mensageiro a dizer: Levantai-vos, e levantemo-nos contra ela para a guerra.");
    b->dados[OBADIAS].capitulos[1].versos[2] = wxT("Eis que te farei pequeno entre as nações; serás muito desprezado.");
    b->dados[OBADIAS].capitulos[1].versos[3] = wxT("A soberba do teu coração te enganou, ó tu que habitas nas fendas do penhasco, na tua alta morada, que dizes no teu coração: Quem me derrubará em terra?");
    b->dados[OBADIAS].capitulos[1].versos[4] = wxT("Embora subas ao alto como águia, e embora se ponha o teu ninho entre as estrelas, dali te derrubarei, diz o Senhor.");
    b->dados[OBADIAS].capitulos[1].versos[5] = wxT("Se a ti viessem ladrões, ou roubadores de noite {como estás destruído!}, não furtariam somente o que lhes bastasse? se a ti viessem os vindimadores, não deixariam umas uvas de rabisco?");
    b->dados[OBADIAS].capitulos[1].versos[6] = wxT("Como foram rebuscados os bens de Esaú! como foram esquadrinhados os seus tesouros ocultos!");
    b->dados[OBADIAS].capitulos[1].versos[7] = wxT("Todos os teus confederados te levaram para fora dos teus limites; os que estavam de paz contigo te enganaram, e prevaleceram contra ti; os que comem o teu pão põem debaixo de ti uma armadilha; não há em Edom entendimento.");
    b->dados[OBADIAS].capitulos[1].versos[8] = wxT("Acaso não acontecerá naquele dia, diz o Senhor, que farei perecer os sábios de Edom, e o entendimento do monte de Esaú?");
    b->dados[OBADIAS].capitulos[1].versos[9] = wxT("E os teus valentes, ó Temã, estarão atemorizados, para que do monte de Esaú seja cada um exterminado pela matança.");
    b->dados[OBADIAS].capitulos[1].versos[10] = wxT("Por causa da violência feita a teu irmão Jacó, cobrir-te-á a confusão, e serás exterminado para sempre.");
    b->dados[OBADIAS].capitulos[1].versos[11] = wxT("No dia em que estiveste do lado oposto, no dia em que estranhos lhe levaram os bens, e os estrangeiros lhe entraram pelas portas e lançaram sortes sobre Jerusalém, tu mesmo eras como um deles.");
    b->dados[OBADIAS].capitulos[1].versos[12] = wxT("Mas tu não devias olhar com prazer para o dia de teu irmão no dia do seu desterro, nem alegrar-te sobre os filhos de Judá no dia da sua ruína, nem falar arrogantemente no dia da tribulação;");
    b->dados[OBADIAS].capitulos[1].versos[13] = wxT("nem entrar pela porta do meu povo no dia da sua calamidade; sim, tu não devias olhar, satisfeito, para o seu mal, no dia da sua calamidade; nem lançar mão dos seus bens no dia da sua calamidade;");
    b->dados[OBADIAS].capitulos[1].versos[14] = wxT("nem te postar nas encruzilhadas, para exterminares os que escapassem; nem entregar os que lhe restassem, no dia da tribulação.");
    b->dados[OBADIAS].capitulos[1].versos[15] = wxT("Porquanto o dia do Senhor está perto, sobre todas as nações, como tu fizeste, assim se fará contigo; o teu feito tornará sobre a tua cabeça.");
    b->dados[OBADIAS].capitulos[1].versos[16] = wxT("Pois como vós bebestes no meu santo monte, assim beberão de contínuo todas as nações; sim, beberão e sorverão, e serão como se nunca tivessem sido.");
    b->dados[OBADIAS].capitulos[1].versos[17] = wxT("Mas no monte de Sião haverá livramento, e ele será santo; e os da casa de Jacó possuirão as suas herdades.");
    b->dados[OBADIAS].capitulos[1].versos[18] = wxT("E a casa de Jacó será um fogo, e a casa de José uma chama, e a casa de Esaú restolho; aqueles se acenderão contra estes, e os consumirão; e ninguém mais restará da casa de Esaú; porque o Senhor o disse.");
    b->dados[OBADIAS].capitulos[1].versos[19] = wxT("Ora, os do Negebe possuirão o monte de Esaú, e os da planície, os filisteus; possuirão também os campos de Efraim, e os campos de Samária; e Benjamim possuirá a Gileade.");
    b->dados[OBADIAS].capitulos[1].versos[20] = wxT("Os cativos deste exército dos filhos de Israel possuirão os cananeus até Zarefate; e os cativos de Jerusalém, que estão em Sefarade, possuirão as cidades do Negebe.");
    b->dados[OBADIAS].capitulos[1].versos[21] = wxT("Subirão salvadores ao monte de Sião para julgarem o monte de Esaú; e o reino será do Senhor.");

}
